import{_ as a,O as r,H as o,f as d,k as s,i as p}from"./chunks/framework.Pt2pSV98.js";const f=JSON.parse('{"title":"提示词知识测验","description":"检验你对 Prompt 工程核心技巧的掌握——System Prompt、Few-Shot、CoT、JSON Mode","frontmatter":{"title":"提示词知识测验","description":"检验你对 Prompt 工程核心技巧的掌握——System Prompt、Few-Shot、CoT、JSON Mode","difficulty":"beginner"},"headers":[],"relativePath":"prompts/quiz.md","filePath":"prompts/quiz.md"}'),h={name:"prompts/quiz.md"};function n(l,t,m,i,u,c){const e=r("DifficultyBadge");return o(),d("div",null,[s(e,{level:"beginner"}),t[0]||(t[0]=p(`<h1 id="📝-提示词知识测验" tabindex="-1">📝 提示词知识测验 <a class="header-anchor" href="#📝-提示词知识测验" aria-label="Permalink to &quot;📝 提示词知识测验&quot;">​</a></h1><p>学完提示词工程模块后，来测测你的掌握情况！共 5 题，每题后附答案和解析。</p><hr><h2 id="一、选择题" tabindex="-1">一、选择题 <a class="header-anchor" href="#一、选择题" aria-label="Permalink to &quot;一、选择题&quot;">​</a></h2><h3 id="q1-system-prompt-的主要作用是什么" tabindex="-1">Q1：System Prompt 的主要作用是什么？ <a class="header-anchor" href="#q1-system-prompt-的主要作用是什么" aria-label="Permalink to &quot;Q1：System Prompt 的主要作用是什么？&quot;">​</a></h3><pre><code>A. 控制模型输出的字数
B. 设定模型的行为、角色和规则
C. 决定模型使用什么语言
D. 设置模型的运行温度
</code></pre><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>System Prompt 用于在对话开始前定义模型的整体行为——你是谁、你的职责、你的限制、你的输出风格等。它像是一份&quot;员工手册&quot;，决定了 AI 如何回应所有后续的用户输入。</p><p>💡 关联阅读：<a href="/ai-knowledge/prompts/system-prompt.html">System Prompt 设计</a> · <a href="/ai-knowledge/prompts/role-prompting.html">角色设定</a></p></details><hr><h3 id="q2-few-shot-提示是什么意思" tabindex="-1">Q2：Few-Shot 提示是什么意思？ <a class="header-anchor" href="#q2-few-shot-提示是什么意思" aria-label="Permalink to &quot;Q2：Few-Shot 提示是什么意思？&quot;">​</a></h3><pre><code>A. 只用一个词提问
B. 给模型 2-3 个示例后再提问
C. 让模型自己举例子
D. 限制模型的输出长度
</code></pre><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>Few-Shot 提示是在提问前给模型展示几个示例（通常 2-5 个），让模型通过示例理解你期望的格式、风格和逻辑。与之对应的是 Zero-Shot（不给示例直接提问）。</p><p>💡 关联阅读：<a href="/ai-knowledge/prompts/few-shot.html">Few-Shot / Zero-Shot</a></p></details><hr><h3 id="q3-思维链-cot-最适合什么场景" tabindex="-1">Q3：思维链（CoT）最适合什么场景？ <a class="header-anchor" href="#q3-思维链-cot-最适合什么场景" aria-label="Permalink to &quot;Q3：思维链（CoT）最适合什么场景？&quot;">​</a></h3><pre><code>A. 简单问答
B. 数学推理和逻辑分析
C. 文本翻译
D. 内容摘要
</code></pre><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>思维链（Chain of Thought）通过引导模型&quot;一步一步思考&quot;，显著提升在数学推理、逻辑推演、多步骤问题解决等复杂任务上的准确率。简单问答不需要 CoT，用了反而是浪费 Token。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/cot.html">思维链 (CoT)</a> · <a href="/ai-knowledge/prompts/structured-prompt.html">结构化提示词</a></p></details><hr><h3 id="q4-json-mode-的主要用途是" tabindex="-1">Q4：JSON Mode 的主要用途是？ <a class="header-anchor" href="#q4-json-mode-的主要用途是" aria-label="Permalink to &quot;Q4：JSON Mode 的主要用途是？&quot;">​</a></h3><pre><code>A. 让模型输出更快的 JSON 格式
B. 强制模型输出可解析的 JSON
C. 把模型内部状态转为 JSON
D. 优化模型的 JSON 训练数据
</code></pre><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>JSON Mode 确保模型输出的是合法 JSON 格式，可以直接被程序解析使用。这对于 AI 开发至关重要——当 LLM 的输出需要被下游代码消费时（如 Tool Calling、API 响应），必须保证格式正确。</p><p>💡 关联阅读：<a href="/ai-knowledge/dev/structured-output.html">结构化输出 (JSON Mode)</a> · <a href="/ai-knowledge/dev/tool-calling.html">Tool Calling</a></p></details><hr><h2 id="二、判断题" tabindex="-1">二、判断题 <a class="header-anchor" href="#二、判断题" aria-label="Permalink to &quot;二、判断题&quot;">​</a></h2><h3 id="q5-写-prompt-时-越详细的指令通常会得到更好的结果。" tabindex="-1">Q5：写 Prompt 时，越详细的指令通常会得到更好的结果。 <a class="header-anchor" href="#q5-写-prompt-时-越详细的指令通常会得到更好的结果。" aria-label="Permalink to &quot;Q5：写 Prompt 时，越详细的指令通常会得到更好的结果。&quot;">​</a></h3><details><summary>查看答案</summary><p><strong>✅ 正确</strong></p><p>AI 不是人，它无法&quot;揣摩&quot;你的意图。指令越具体、约束越明确、上下文越丰富，模型的输出就越符合预期。这也是「清晰指令五原则」的核心思想——好的 Prompt 是精确的蓝图，不是模糊的愿望。</p><p>💡 关联阅读：<a href="/ai-knowledge/prompts/principles.html">清晰指令五原则</a> · <a href="/ai-knowledge/terms/prompt.html">写好 Prompt 的核心原则</a></p></details><hr><h2 id="📊-评分" tabindex="-1">📊 评分 <a class="header-anchor" href="#📊-评分" aria-label="Permalink to &quot;📊 评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>正确数</th><th>等级</th></tr></thead><tbody><tr><td>5</td><td>🏆 满分！提示词高手</td></tr><tr><td>3-4</td><td>👍 掌握良好</td></tr><tr><td>1-2</td><td>📖 仍需加强</td></tr><tr><td>0</td><td>🔄 建议重读提示词模块</td></tr></tbody></table><details><summary>你对了几题？来对答案吧！</summary><table tabindex="0"><thead><tr><th>题号</th><th>答案</th><th>类型</th></tr></thead><tbody><tr><td>Q1</td><td>B</td><td>选择题</td></tr><tr><td>Q2</td><td>B</td><td>选择题</td></tr><tr><td>Q3</td><td>B</td><td>选择题</td></tr><tr><td>Q4</td><td>B</td><td>选择题</td></tr><tr><td>Q5</td><td>✅</td><td>判断题</td></tr></tbody></table></details>`,27))])}const b=a(h,[["render",n]]);export{f as __pageData,b as default};
